SELECT SUM(total_feed_consumed) AS total_feed_consumed
FROM feed_consumption
WHERE flock_id = 1 AND date BETWEEN '2023-03-01' AND '2023-05-31';

SELECT SUM(total_feed_consumed) AS total_feed_consumed
FROM feed_consumption
WHERE date >= '2023-01-01' AND date <= '2023-12-31';

SELECT AVG(fc.feed_cost) AS average_feed_cost
FROM feed_consumption fc
WHERE fc.date BETWEEN '2023-05-01' AND '2023-05-02';

SELECT total_feed_consumed
FROM feed_consumption
WHERE date = '2023-05-02' AND flock_id = 1;

SELECT flock_name, current_population
FROM flocks
WHERE status = 'active' AND current_population > 1000;

SELECT MAX(initial_population) AS max_initial_population
FROM flocks
WHERE breed = 'Hy-Line Brown';

SELECT flock_name
FROM flocks
WHERE flock_id = 1;

SELECT SUM(initial_population) AS total_initial_population
FROM flocks
WHERE breed = 'Hy-Line Brown';

SELECT flock_id, SUM(total_feed_consumed) AS total_feed_consumed
FROM feed_consumption
GROUP BY flock_id;

SELECT supplier_name
FROM feed_supplier
WHERE pricing < 0.15;
